#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <vector>
#include <iostream>
#include <sys/time.h>
#include <sys/stat.h>

// Inline definitions from headers to avoid missing dependencies
typedef struct {
    float lat;
    float lng;
} LatLong;

typedef struct {
    char recString[49];
    float distance;
} Record;

#define REC_LENGTH 49

// CUDA Kernel equivalent to OpenCL NearestNeighbor
__global__ void NearestNeighbor(LatLong *d_locations,
                                float *d_distances,
                                const int numRecords,
                                const float lat,
                                const float lng) {
    int globalId = threadIdx.x + blockIdx.x * blockDim.x;

    if (globalId < numRecords) {
        LatLong *latLong = d_locations + globalId;
        float *dist = d_distances + globalId;
        *dist = (float)sqrt((lat - latLong->lat) * (lat - latLong->lat) +
                            (lng - latLong->lng) * (lng - latLong->lng));
    }
}

// Utility functions inline
void* alloc(size_t size) {
    void* ptr = NULL;
    ptr = malloc(size);
    if (ptr == NULL) {
        perror("malloc");
        exit(-1);
    }
    return ptr;
}

void checkFile(char* filename) {
    struct stat fileStatus;
    if (stat(filename, &fileStatus) != 0) {
        printf("Error opening file: %s\n", filename);
        exit(-1);
    } else {
        if (!(S_IFREG & fileStatus.st_mode)) {
            printf("File %s is not a regular file\n", filename);
            exit(-1);
        }
    }
}

void checkDir(char* dirpath) {
    struct stat fileStatus;
    if (stat(dirpath, &fileStatus) != 0) {
        printf("Directory does not exist: %s\n", dirpath);
        exit(-1);
    } else {
        if (!(S_IFDIR & fileStatus.st_mode)) {
            printf("Directory was not provided: %s\n", dirpath);
            exit(-1);
        }
    }
}

unsigned int roundUp(unsigned int value, unsigned int multiple) {
    unsigned int remainder = value % multiple;
    if (remainder != 0) {
        value += (multiple - remainder);
    }
    return value;
}

char* smartStrcat(char* str1, char* str2) {
    char* newStr = NULL;
    newStr = (char*)alloc((strlen(str1) + strlen(str2) + 1) * sizeof(char));
    strcpy(newStr, str1);
    strcat(newStr, str2);
    return newStr;
}

// Timing helpers
void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *res) {
    res->tv_sec = t1->tv_sec - t2->tv_sec;
    res->tv_usec = t1->tv_usec - t2->tv_usec;
    if (res->tv_usec < 0) {
        res->tv_sec--;
        res->tv_usec += 1000000;
    }
}

// CUDA Initialization and Management
void cuda_init_context(int platform, int dev, int quiet) {
    // In CUDA, we don't have platforms/devices in the same sense as OpenCL.
    // We just ensure CUDA is initialized.
    int deviceCount = 0;
    cudaError_t err = cudaGetDeviceCount(&deviceCount);
    if (err != cudaSuccess || deviceCount == 0) {
        printf("No CUDA devices found\n");
        exit(-1);
    }
    if (!quiet) {
        printf("Number of CUDA devices detected: %d\n", deviceCount);
        printf("Using Device %d\n", (dev >= 0 && dev < deviceCount) ? dev : 0);
    }
    int chosen_device = (dev >= 0 && dev < deviceCount) ? dev : 0;
    cudaSetDevice(chosen_device);
}

void cuda_cleanup() {
    cudaDeviceReset();
}

cudaError_t cuda_allocBuffer(void** devPtr, size_t mem_size) {
    return cudaMalloc(devPtr, mem_size);
}

void cuda_freeBuffer(void* devPtr) {
    cudaFree(devPtr);
}

cudaError_t cuda_copyBufferToDevice(void* dst, void* src, size_t mem_size) {
    return cudaMemcpy(dst, src, mem_size, cudaMemcpyHostToDevice);
}

cudaError_t cuda_copyBufferToHost(void* dst, void* src, size_t mem_size) {
    return cudaMemcpy(dst, src, mem_size, cudaMemcpyDeviceToHost);
}

// Main logic translated from OpenClFindNearestNeighbors
float *CUDAFindNearestNeighbors(
    int numRecords,
    std::vector<LatLong> &locations,
    float lat, float lng,
    int timing) {

    LatLong *d_locations = NULL;
    float *d_distances = NULL;
    cudaError_t err;

    struct timeval tv, tv_mem_alloc_start, tv_mem_alloc_end;
    float mem_alloc_time = 0;

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    err = cuda_allocBuffer((void**)&d_locations, sizeof(LatLong) * numRecords);
    if (err != cudaSuccess) {
        fprintf(stderr, "Failed to allocate device memory for locations\n");
        exit(-1);
    }

    err = cuda_allocBuffer((void**)&d_distances, sizeof(float) * numRecords);
    if (err != cudaSuccess) {
        fprintf(stderr, "Failed to allocate device memory for distances\n");
        exit(-1);
    }

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    // Copy data to device
    err = cuda_copyBufferToDevice(d_locations, &locations[0], sizeof(LatLong) * numRecords);
    if (err != cudaSuccess) {
        fprintf(stderr, "Failed to copy locations to device\n");
        exit(-1);
    }

    // Setup kernel parameters
    int blockSize = 64;
    int numBlocks = (numRecords + blockSize - 1) / blockSize;

    // Launch kernel
    NearestNeighbor<<<numBlocks, blockSize>>>(d_locations, d_distances, numRecords, lat, lng);

    err = cudaDeviceSynchronize();
    if (err != cudaSuccess) {
        fprintf(stderr, "Kernel execution failed\n");
        exit(-1);
    }

    // Copy results back
    float *distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "Failed to allocate host memory for results\n");
        exit(-1);
    }

    err = cuda_copyBufferToHost(distances, d_distances, sizeof(float) * numRecords);
    if (err != cudaSuccess) {
        fprintf(stderr, "Failed to copy distances to host\n");
        exit(-1);
    }

    if (timing) {
        printf("# Records\tAlloc(s)\t\tTotal(s)\n");
        printf("%d        \t%f\t\t-\n", numRecords, mem_alloc_time / 1000.0);
    }

    // Cleanup device memory
    cuda_freeBuffer(d_locations);
    cuda_freeBuffer(d_distances);

    return distances;
}

// Data loading and processing functions (unchanged logic)
char *data_folder = NULL;

int loadData(char *filename, std::vector<Record> &records, std::vector<LatLong> &locations) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "error opening filelist\n");
        exit(0);
    }

    while (!feof(flist)) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        sprintf(db_fullname, "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while (!feof(fp)) {
            Record record;
            LatLong latLong;
            if (fgets(record.recString, 49, fp) == NULL) break;
            // Remove newline if present
            size_t len = strlen(record.recString);
            if (len > 0 && record.recString[len-1] == '\n') {
                record.recString[len-1] = '\0';
            }
            if (strlen(record.recString) < 38) continue; // Ensure string is long enough

            char substr[6];
            for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(std::vector<Record> &records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records[i];
        records[i] = records[minLoc];
        records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
            case 'r':
                i++;
                *r = atoi(argv[i]);
                break;
            case 'l':
                if (argv[i][2] == 'a') {
                    *lat = atof(argv[i + 1]);
                } else {
                    *lng = atof(argv[i + 1]);
                }
                i++;
                break;
            case 'h':
                return 1;
                break;
            case 'q':
                *q = 1;
                break;
            case 't':
                *t = 1;
                break;
            case 'p':
                i++;
                *p = atoi(argv[i]);
                break;
            case 'd':
                i++;
                *d = atoi(argv[i]);
                break;
            case 'f':
                i++;
                data_folder = argv[i];
                break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

void printUsage() {
    printf("Nearest Neighbor Usage\n");
    printf("\n");
    printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
    printf("\n");
    printf("filename     the filename that lists the data input files\n");
    printf("-r [int]     the number of records to return (default: 10)\n");
    printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
    printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
    printf("\n");
    printf("-h, --help   Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}

int main(int argc, char *argv[]) {
    std::vector<Record> records;
    float *recordDistances;

    std::vector<LatLong> locations;
    int i;

    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    int numRecords = loadData(filename, records, locations);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (resultsCount > numRecords) resultsCount = numRecords;

    struct timeval tv_total_start, tv_init_end, tv;
    float init_time = 0, total_time = 0;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    cuda_init_context(platform, device, quiet);

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    recordDistances = CUDAFindNearestNeighbors(numRecords, locations, lat, lng, timing);

    findLowest(records, recordDistances, numRecords, resultsCount);

    if (!quiet)
        for (i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
        }

    free(recordDistances);
    cuda_cleanup();

#ifdef TIMING
    struct timeval tv_close_end;
    float close_time = 0;
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    close_time = total_time - init_time; // Approximate

    printf("Init: %f\n", init_time);
    printf("Exec+Mem: %f\n", total_time - init_time);
    printf("Total: %f\n", total_time);
#endif

    return 0;
}
